sql:
SELECT COUNT(*) AS game_history_count
FROM player_game_history
WHERE player_id = 0;

SELECT summary, summary_date
FROM game_summaries
WHERE summary_id = 0;

SELECT game_id, rating, rating_date, rating_author_id
FROM game_ratings
ORDER BY rating DESC;

SELECT outcome
FROM game_outcomes
WHERE outcome_date = (
  SELECT MAX(outcome_date)
  FROM game_outcomes
);

SELECT format_name
FROM game_formats
WHERE time_control = '60+0';

SELECT COUNT(*) 
FROM move_analyses 
WHERE move_id = 1;

SELECT move, move_duration, NTILE(3) OVER (ORDER BY move_duration) AS duration_group
FROM moves
WHERE move_number > 10;
